    pub const UNSAFE_INPUT_BLOCKED: &str = "STAGE30_UNSAFE_INPUT_BLOCKED";
    pub const RUNTIME_MOCK_BLOCKED: &str = "STAGE30_RUNTIME_MOCK_BLOCKED";
